#include<bits/stdc++.h>
using namespace std;
map<string,bool> mmap;
map<string,int> map2;
int n;
bool check(string s)
{
    if(mmap.count(s)) return mmap[s];
    int t=s.find(":");
    if(t==string::npos) return false;
    int t2=0,t3,num=0;
    for(int i=1;i<=3;i++)
    {
        t3=s.find(".",t2);
        if(t3==string::npos||t2==t3||((t3-t2)>3)||(s[t2]=='0'&&t3-t2>1)) return false;
        for(int i=t2;i<t3;i++)
        {
            num=num*10+s[i]-'0';
        }
        if(num>255) return false;
        t2=t3+1;
        num=0;
    }
    if(s.find(".",t2)!=string::npos||s.find(":",t+1)!=string::npos) return false;
    if(t-t2>3||(s[t2]=='0'&&t-t2>1)||t2==t) return false;
    for(int i=t2;i<t;i++) num=num*10+s[i]-'0';
    if(num>255) return false;
    num=0;
    if((s.size()-t)>6||(s[t+1]=='0'&&(s.size()-t-1>1))||t+1==s.size()) return false;
    for(int i=t+1;i<s.size();i++) num=num*10+s[i]-'0';
    if(num>65535) return false;
    return true;
}
int main()
{
    // freopen("P7911_13.in","r",stdin);
    // freopen("c.out","w",stdout);
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        int op;
        string s;
        cin>>s;
        if(s[0]=='S') op=0;//服务
        else op=1;
        cin>>s;
        if(!check(s))
        {
            mmap[s]=false;
            cout<<"ERR\n";
            continue;
        }
        mmap[s]=true;
        if(op==0)
        {
            if(map2.count(s)) cout<<"FAIL\n";
            else
            {
                cout<<"OK\n";
                map2[s]=i;
            }
        }
        else
        {
            if(map2.count(s)) cout<<map2[s]<<'\n';
            else cout<<"FAIL\n";
        }
    }
    return 0;
}
